/** Get default indexer configuration */
export function getDefaultConfig(
  rootDir: string,
  policyInput?: IndexScopePolicy | ResolveIndexScopePolicyInput,
): IndexerConfig {
  const scopePolicy = policyInput && 'fingerprint' in policyInput
    ? policyInput
    : resolveIndexScopePolicy(policyInput);
  // Default scope excludes internal-heavy .opencode folders unless the caller opts in.
  const excludeGlobs = [
    '**/node_modules/**',
    '**/dist/**',
    '**/.git/**',
    '**/vendor/**',
    '**/external/**',
    '**/z_future/**',
    '**/z_archive/**',
    ...scopePolicy.excludedSkillGlobs,
    ...scopePolicy.excludedAgentGlobs,
    ...scopePolicy.excludedCommandGlobs,
    ...scopePolicy.excludedSpecGlobs,
    ...scopePolicy.excludedPluginGlobs,
    ...scopePolicy.excludeGlobs,
  ];

  const defaultIncludeGlobs = [
    '**/*.ts',
    '**/*.tsx',
    '**/*.mts',
    '**/*.cts',
    '**/*.js',
    '**/*.jsx',
    '**/*.mjs',
    '**/*.cjs',
    '**/*.py',
    '**/*.sh',
    '**/*.bash',
    '**/*.zsh',
    // Markdown/prose docs are deliberately NOT indexed: the code graph models code
    // structure and structured config, not documentation. Config formats below still
    // index as `language='doc'` rows. A caller can re-add docs per-scan via includeGlobs.
    '**/*.json',
    '**/*.jsonc',
    '**/*.yaml',
    '**/*.yml',
    '**/*.toml',
  ];

  return {
    rootDir,
    includeGlobs: scopePolicy.includeGlobs.length > 0
      ? [...scopePolicy.includeGlobs]
      : defaultIncludeGlobs,
    excludeGlobs,
    maxFileSizeBytes: 102_400,
    languages: ['javascript', 'typescript', 'python', 'bash', 'doc'],
    scopePolicy,
  };

